"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[9671],{52493(n,r,t){t.r(r),t.d(r,{assets:()=>c,contentTitle:()=>i,default:()=>p,frontMatter:()=>d,metadata:()=>e,toc:()=>o});const e=JSON.parse('{"id":"cpp11/variadic-templates","title":"\u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)","description":"C++11 \u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/20-variadic-templates.md","sourceDirName":"cpp11","slug":"/cpp11/20-variadic-templates","permalink":"/LearnModernCpp/docs/cpp11/20-variadic-templates","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"variadic_templates","permalink":"/LearnModernCpp/docs/tags/variadic-templates"}],"version":"current","sidebarPosition":21,"frontMatter":{"sidebar_position":21,"slug":"20-variadic-templates","title":"\u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)","description":"C++11 \u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates) \u6559\u5b66\u793a\u4f8b","tags":["cpp11","variadic_templates"]},"sidebar":"docs","previous":{"title":"alignof \u4e0e alignas","permalink":"/LearnModernCpp/docs/cpp11/19-alignof-alignas"},"next":{"title":"constexpr \u51fd\u6570\u548c\u53d8\u91cf","permalink":"/LearnModernCpp/docs/cpp11/21-constexpr"}}');var s=t(74848),a=t(28453);const d={sidebar_position:21,slug:"20-variadic-templates",title:"\u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)",description:"C++11 \u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates) \u6559\u5b66\u793a\u4f8b",tags:["cpp11","variadic_templates"]},i="\u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)",c={},o=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,a.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(r.header,{children:(0,s.jsx)(r.h1,{id:"\u53ef\u53d8\u53c2\u6570\u6a21\u677f-variadic-templates",children:"\u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)"})}),"\n",(0,s.jsx)(r.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 \u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(r.pre,{children:(0,s.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp11/20_variadic_templates.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u5141\u8bb8\u6a21\u677f\u63a5\u53d7\u4efb\u610f\u6570\u91cf\u548c\u7c7b\u578b\u7684\u53c2\u6570\uff0c\u901a\u8fc7\u53c2\u6570\u5305(parameter pack)\r\n *          \u548c\u5305\u5c55\u5f00(pack expansion)\u5b9e\u73b0\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++03\u4e2d\u8981\u652f\u6301\u591a\u4e2a\u53c2\u6570\u7684\u6a21\u677f\uff0c\u9700\u8981\u4e3a\u6bcf\u79cd\u53c2\u6570\u6570\u91cf\u5199\r\n *   \u4e00\u4e2a\u7279\u5316\u7248\u672c\uff08\u5982tuple\u9700\u8981N\u4e2a\u7248\u672c\uff09\u3002\u53ef\u53d8\u53c2\u6570\u6a21\u677f\u8ba9\u4e00\u4e2a\u6a21\u677f\r\n *   \u5c31\u80fd\u5904\u7406\u4efb\u610f\u6570\u91cf\u7684\u53c2\u6570\uff0c\u662f\u5b9e\u73b0tuple\u3001make_shared\u7b49\u7684\u57fa\u7840\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - typename... Args \u58f0\u660e\u6a21\u677f\u53c2\u6570\u5305\r\n *   - Args... args \u58f0\u660e\u51fd\u6570\u53c2\u6570\u5305\r\n *   - sizeof...(Args) \u83b7\u53d6\u53c2\u6570\u5305\u4e2d\u7684\u53c2\u6570\u6570\u91cf\r\n *   - \u9012\u5f52\u5c55\u5f00\u662f\u6700\u5e38\u7528\u7684\u5305\u5c55\u5f00\u65b9\u5f0f\r\n *   - \u53c2\u6570\u5305\u53ef\u4ee5\u5728\u591a\u79cd\u4e0a\u4e0b\u6587\u4e2d\u5c55\u5f00\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <sstream>\r\n#include <tuple>\r\n#include <vector>\r\n#include <memory>\r\n#include <type_traits>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u6700\u7b80\u5355\u7684\u53ef\u53d8\u53c2\u6570\u51fd\u6570\u6a21\u677f \u2014\u2014 \u9012\u5f52\u5c55\u5f00\r\n// \u9012\u5f52\u7ec8\u6b62\u6761\u4ef6\uff08\u57fa\u7840\u60c5\u51b5\uff09\r\nvoid print() {\r\n    std::cout << std::endl; // \u65e0\u53c2\u6570\u65f6\u7ed3\u675f\u9012\u5f52\r\n}\r\n\r\n// \u9012\u5f52\u5c55\u5f00\r\ntemplate <typename T, typename... Args>\r\nvoid print(const T& first, const Args&... rest) {\r\n    std::cout << first;\r\n    if (sizeof...(rest) > 0) {\r\n        std::cout << ", ";\r\n    }\r\n    print(rest...); // \u9012\u5f52\u8c03\u7528\uff0c\u53c2\u6570\u5305\u6bcf\u6b21\u5c11\u4e00\u4e2a\r\n}\r\n\r\n// 2. sizeof... \u83b7\u53d6\u53c2\u6570\u6570\u91cf\r\ntemplate <typename... Args>\r\nvoid count_args(const Args&... args) {\r\n    std::cout << "  \u53c2\u6570\u6570\u91cf: " << sizeof...(Args)\r\n              << " (\u7c7b\u578b\u5305), " << sizeof...(args)\r\n              << " (\u503c\u5305)" << std::endl;\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "===== \u57fa\u7840\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. print\u53ef\u4ee5\u63a5\u53d7\u4efb\u610f\u6570\u91cf\u3001\u4efb\u610f\u7c7b\u578b\u7684\u53c2\u6570\r\n    std::cout << "print(): ";\r\n    print();\r\n\r\n    std::cout << "print(1): ";\r\n    print(1);\r\n\r\n    std::cout << "print(1, 2.5, \\"\u4f60\u597d\\"): ";\r\n    print(1, 2.5, "\u4f60\u597d");\r\n\r\n    std::cout << "print(true, \'A\', 3.14, \\"\u4e16\u754c\\", 42): ";\r\n    print(true, \'A\', 3.14, "\u4e16\u754c", 42);\r\n\r\n    // 2. sizeof...\r\n    std::cout << "\\nsizeof...:" << std::endl;\r\n    count_args();\r\n    count_args(1);\r\n    count_args(1, 2.0, "\u4e09", \'4\');\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u7c7b\u578b\u5b89\u5168\u7684printf\uff08\u66ff\u4ee3C\u7684printf\uff09\r\nvoid safe_printf(const char* format) {\r\n    // \u57fa\u7840\u60c5\u51b5\uff1a\u53ea\u5269\u683c\u5f0f\u5b57\u7b26\u4e32\r\n    while (*format) {\r\n        if (*format == \'%\') {\r\n            throw std::runtime_error("safe_printf: \u683c\u5f0f\u53c2\u6570\u591a\u4e8e\u5b9e\u9645\u53c2\u6570!");\r\n        }\r\n        std::cout << *format++;\r\n    }\r\n}\r\n\r\ntemplate <typename T, typename... Args>\r\nvoid safe_printf(const char* format, const T& value, const Args&... args) {\r\n    while (*format) {\r\n        if (*format == \'%\') {\r\n            std::cout << value;\r\n            safe_printf(format + 1, args...); // \u9012\u5f52\u5904\u7406\u5269\u4f59\u53c2\u6570\r\n            return;\r\n        }\r\n        std::cout << *format++;\r\n    }\r\n    throw std::runtime_error("safe_printf: \u5b9e\u9645\u53c2\u6570\u591a\u4e8e\u683c\u5f0f\u53c2\u6570!");\r\n}\r\n\r\n// 2. \u6c42\u548c\uff08\u4efb\u610f\u6570\u91cf\u7684\u6570\u503c\u53c2\u6570\uff09\r\ntemplate <typename T>\r\nT sum(T value) {\r\n    return value;\r\n}\r\n\r\ntemplate <typename T, typename... Args>\r\nT sum(T first, Args... rest) {\r\n    return first + sum(rest...);\r\n}\r\n\r\n// 3. \u7b80\u5316\u7248make_unique\uff08C++14\u624d\u6b63\u5f0f\u52a0\u5165\u6807\u51c6\u5e93\uff09\r\ntemplate <typename T, typename... Args>\r\nstd::unique_ptr<T> my_make_unique(Args&&... args) {\r\n    return std::unique_ptr<T>(new T(std::forward<Args>(args)...));\r\n}\r\n\r\n// 4. \u7b80\u5316\u7248tuple\uff08\u5c55\u793a\u53ef\u53d8\u53c2\u6570\u7c7b\u6a21\u677f\uff09\r\n// \u7a7atuple\uff08\u57fa\u7840\u60c5\u51b5\uff09\r\ntemplate <typename... Types>\r\nstruct MyTuple {};\r\n\r\n// \u9012\u5f52\u5b9a\u4e49\r\ntemplate <typename Head, typename... Tail>\r\nstruct MyTuple<Head, Tail...> : MyTuple<Tail...> {\r\n    Head value;\r\n\r\n    MyTuple() = default;\r\n    MyTuple(const Head& h, const Tail&... t)\r\n        : MyTuple<Tail...>(t...), value(h) {}\r\n};\r\n\r\n// 5. \u53c2\u6570\u5305\u5c55\u5f00\u7684\u5176\u4ed6\u4e0a\u4e0b\u6587\r\ntemplate <typename... Args>\r\nvoid expand_demo(const Args&... args) {\r\n    // \u5c55\u5f00\u4e3a\u9017\u53f7\u5206\u9694\u7684\u8868\u8fbe\u5f0f\uff08\u6bcf\u4e2a\u53c2\u6570\u52a01\u540e\u5b58\u5165vector\uff09\r\n    // \u4f7f\u7528\u521d\u59cb\u5316\u5217\u8868\u6280\u5de7\u8fdb\u884c\u5c55\u5f00\r\n    std::vector<int> v = { (std::cout << args << " ", 0)... };\r\n    std::cout << std::endl;\r\n    (void)v;\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n===== \u8fdb\u9636\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. \u7c7b\u578b\u5b89\u5168\u7684printf\r\n    std::cout << "safe_printf:" << std::endl;\r\n    std::cout << "  ";\r\n    safe_printf("\u59d3\u540d: %, \u5e74\u9f84: %, \u6210\u7ee9: %\\n", "\u5f20\u4e09", 25, 95.5);\r\n\r\n    // 2. \u4efb\u610f\u53c2\u6570\u6c42\u548c\r\n    std::cout << "\\n\u6c42\u548c:" << std::endl;\r\n    std::cout << "  sum(1,2,3,4,5) = " << sum(1, 2, 3, 4, 5) << std::endl;\r\n    std::cout << "  sum(1.1, 2.2, 3.3) = " << sum(1.1, 2.2, 3.3) << std::endl;\r\n\r\n    // 3. my_make_unique\r\n    struct Person {\r\n        std::string name;\r\n        int age;\r\n        Person(const std::string& n, int a) : name(n), age(a) {}\r\n    };\r\n    auto p = my_make_unique<Person>("\u674e\u56db", 30);\r\n    std::cout << "\\nmy_make_unique: " << p->name << ", " << p->age << std::endl;\r\n\r\n    // 4. MyTuple\r\n    MyTuple<int, double, std::string> t(42, 3.14, "hello");\r\n    std::cout << "\\nMyTuple\u7b2c\u4e00\u4e2a\u5143\u7d20: " << t.value << std::endl;\r\n\r\n    // 5. \u5305\u5c55\u5f00\u6f14\u793a\r\n    std::cout << "\\n\u5305\u5c55\u5f00: ";\r\n    expand_demo(1, "\u4f60\u597d", 3.14, true);\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\n\r\n// \u7f16\u8bd1\u65f6\u9012\u5f52\u7684\u6df1\u5ea6\u9650\u5236\r\ntemplate <int N>\r\nstruct Factorial {\r\n    static const int value = N * Factorial<N - 1>::value;\r\n};\r\n\r\ntemplate <>\r\nstruct Factorial<0> {\r\n    static const int value = 1;\r\n};\r\n\r\n// \u5c55\u793a\u53c2\u6570\u5305\u7684\u6b63\u786e\u5c55\u5f00\u4f4d\u7f6e\r\ntemplate <typename... Args>\r\nvoid expand_patterns(const Args&... args) {\r\n    // \u6b63\u786e\u7684\u5c55\u5f00\u6a21\u5f0f:\r\n    // args...           \u5c55\u5f00\u4e3a: arg1, arg2, arg3\r\n    // func(args)...     \u5c55\u5f00\u4e3a: func(arg1), func(arg2), func(arg3)\r\n    // func(args...)     \u5c55\u5f00\u4e3a: func(arg1, arg2, arg3)  \u6ce8\u610f\u533a\u522b!\r\n\r\n    // \u4ee5\u4e0b\u662f\u5c55\u5f00\u4e3avector\u7684\u6280\u5de7\r\n    auto to_string = [](const auto& v) -> std::string {\r\n        std::ostringstream oss;\r\n        oss << v;\r\n        return oss.str();\r\n    };\r\n\r\n    // func(args)... \u5bf9\u6bcf\u4e2a\u53c2\u6570\u5206\u522b\u8c03\u7528func\r\n    std::vector<std::string> strs = { to_string(args)... };\r\n    for (const auto& s : strs) {\r\n        std::cout << "  [" << s << "]" << std::endl;\r\n    }\r\n}\r\n\r\nvoid pitfalls() {\r\n    std::cout << "\\n===== \u6613\u9519\u70b9\u4e0e\u9677\u9631 =====" << std::endl;\r\n\r\n    // \u9677\u96311: \u5fd8\u8bb0\u9012\u5f52\u7ec8\u6b62\u6761\u4ef6\r\n    std::cout << "\u9677\u96311: \u9012\u5f52\u5c55\u5f00\u5fc5\u987b\u6709\u7ec8\u6b62\u6761\u4ef6(\u57fa\u7840\u60c5\u51b5)" << std::endl;\r\n    std::cout << "  \u5426\u5219\u7f16\u8bd1\u5668\u4f1a\u65e0\u9650\u9012\u5f52\u5b9e\u4f8b\u5316\u6a21\u677f\u76f4\u5230\u8fbe\u5230\u6df1\u5ea6\u9650\u5236" << std::endl;\r\n\r\n    // \u9677\u96312: ...\u7684\u4f4d\u7f6e\u5f88\u91cd\u8981\r\n    std::cout << "\\n\u9677\u96312: \'...\'\u7684\u4f4d\u7f6e\u51b3\u5b9a\u5c55\u5f00\u65b9\u5f0f" << std::endl;\r\n    std::cout << "  f(args...)  = f(a1, a2, a3)       // \u53c2\u6570\u5305\u5c55\u5f00\u4e3a\u591a\u4e2a\u53c2\u6570" << std::endl;\r\n    std::cout << "  f(args)...  = f(a1), f(a2), f(a3) // \u5bf9\u6bcf\u4e2a\u53c2\u6570\u5206\u522b\u8c03\u7528f" << std::endl;\r\n\r\n    // \u6f14\u793a\r\n    std::cout << "\\n\u5c55\u5f00\u6a21\u5f0f\u6f14\u793a:" << std::endl;\r\n    expand_patterns(1, "hello", 3.14);\r\n\r\n    // \u9677\u96313: sizeof...\u8fd4\u56de\u7684\u662f\u53c2\u6570\u6570\u91cf\uff0c\u4e0d\u662f\u5b57\u8282\u5927\u5c0f\r\n    std::cout << "\\n\u9677\u96313: sizeof...\u8fd4\u56de\u53c2\u6570\u6570\u91cf\uff0c\u4e0d\u662f\u5b57\u8282\u6570" << std::endl;\r\n    auto check = [](auto... args) {\r\n        std::cout << "  sizeof...(args) = " << sizeof...(args) << " (\u4e2a\u6570)" << std::endl;\r\n    };\r\n    check(1, 2.0, "\u4e09");\r\n\r\n    // \u9677\u96314: \u7f16\u8bd1\u65f6\u9012\u5f52\u6df1\u5ea6\u9650\u5236\r\n    std::cout << "\\n\u9677\u96314: \u6a21\u677f\u9012\u5f52\u6709\u6df1\u5ea6\u9650\u5236(\u901a\u5e38256-1024)" << std::endl;\r\n    std::cout << "  Factorial<10> = " << Factorial<10>::value << std::endl;\r\n    // Factorial<10000> \u53ef\u80fd\u5bfc\u81f4\u7f16\u8bd1\u9519\u8bef\r\n\r\n    // \u9677\u96315: \u53ef\u53d8\u53c2\u6570\u6a21\u677f\u7684\u8c03\u8bd5\u56f0\u96be\r\n    std::cout << "\\n\u9677\u96315: \u53ef\u53d8\u53c2\u6570\u6a21\u677f\u7684\u9519\u8bef\u4fe1\u606f\u53ef\u80fd\u5f88\u957f" << std::endl;\r\n    std::cout << "  \u5efa\u8bae: \u7528static_assert\u5728\u65e9\u671f\u68c0\u67e5\u7c7b\u578b\u7ea6\u675f" << std::endl;\r\n\r\n    std::cout << "\\n\u6700\u4f73\u5b9e\u8df5:" << std::endl;\r\n    std::cout << "  1. \u603b\u662f\u63d0\u4f9b\u9012\u5f52\u7ec8\u6b62\u7684\u57fa\u7840\u60c5\u51b5" << std::endl;\r\n    std::cout << "  2. \u7528sizeof...\u68c0\u67e5\u53c2\u6570\u6570\u91cf" << std::endl;\r\n    std::cout << "  3. \u914d\u5408std::forward\u5b9e\u73b0\u5b8c\u7f8e\u8f6c\u53d1" << std::endl;\r\n    std::cout << "  4. \u8003\u8651\u4f7f\u7528\u521d\u59cb\u5316\u5217\u8868\u6280\u5de7\u66ff\u4ee3\u9012\u5f52\u5c55\u5f00" << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "========================================" << std::endl;\r\n    std::cout << "  C++11 \u7279\u6027: \u53ef\u53d8\u53c2\u6570\u6a21\u677f" << std::endl;\r\n    std::cout << "========================================" << std::endl;\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(r.ul,{children:["\n",(0,s.jsx)(r.li,{children:(0,s.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/parameter_pack",children:"cppreference: \u53ef\u53d8\u53c2\u6570\u6a21\u677f (Variadic Templates)"})}),"\n"]})]})}function p(n={}){const{wrapper:r}={...(0,a.R)(),...n.components};return r?(0,s.jsx)(r,{...n,children:(0,s.jsx)(l,{...n})}):l(n)}},28453(n,r,t){t.d(r,{R:()=>d,x:()=>i});var e=t(96540);const s={},a=e.createContext(s);function d(n){const r=e.useContext(a);return e.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function i(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:d(n.components),e.createElement(a.Provider,{value:r},n.children)}}}]);